import styled from 'styled-components';

export const HeroContainer = styled.section`
display:flex;
flex-direction:row;
background:#403f4c;
color:rgb(255,255,255);
height:100%;
letter-spacing:.25em;
padding:3em;
.about {
    width:40%;
    display:flex;
    justify-content:center;
    align-items:center;
    flex-wrap:wrap;
}

.about__container {
}

.hero {
    width:60%;
}

@media only screen and (max-width:900px) {
    flex-direction:column;

    .about {
        width:100%;
    }

    .hero {
        width:100%;
    }
}

`
